import PropTypes from "prop-types"
import React from "react"

const SpiceCard = ({spiceId, spiceName, spiceColNum, spiceRowNum, spiceFlavours, compoundId}) => (
  <div
    className={spiceId + ' periodic-table__element periodic-table__element--' + compoundId}
    style={{gridArea: spiceColNum + "/" + spiceRowNum}}>
    <div className='name'>{spiceName}</div>
    <div className='compounds-id'>{compoundId}</div>
  <div className='symbol'>{spiceId}</div>
    <div className='flavours'>{spiceFlavours}</div>
  </div>

)

SpiceCard.propTypes = {
  spiceId: PropTypes.string,
  spiceName: PropTypes.string,
  spiceColNum: PropTypes.number,
  spiceRowNum: PropTypes.number,
  spiceFlavours: PropTypes.string,
  compoundId: PropTypes.string
}

SpiceCard.defaultProps = {
  spiceId: "II",
  spiceName: "Deuh",
  spiceColNum: 2,
  spiceRowNum: 2,
  spiceFlavours: "deuh",
  compoundId: "II",
}

export default SpiceCard
