import React from "react"
import Layout from "../components/layout"
import SEO from "../components/seo"

import SpiceCard from "../components/spices/spiceCard"
import JSONData from "../data/spices.json"
import "../styles/spices.less"

const SpicePage = () => (
  <Layout>
    <SEO title="Periodic table of spices" />
      <div className="periodic-table">
        {JSONData.spices.map((data, index) => {
          console.log(data);
            return <SpiceCard
              key={index}
              spiceId={data.id}
              spiceName={data.name}
              spiceColNum={data.col}
              spiceRowNum={data.row}
              spiceFlavours={data.flavours.join(' - ')}
              compoundId={JSONData.compounds[data.compound_id].id}
            />
          })}
      </div>
  </Layout>
)

export default SpicePage


